[{"Patents_info": "PANASONIC IP MAN CO LTD holds the US patent application (ID US-201916293577-A), with publication number US-11081687-B2.", "kind_code": "B2", "application_kind": "A", "pct_number": "None", "family_id": "62241432", "title_localized": "[
