                day = int(groups[1])
                year = int(groups[2])
                if month_str in month_map:
                    month = month_map[month_str]
                    return datetime(year, month, day)
            elif len(groups) == 2:
                month_str = groups[0][:3].lower()
                year = int(groups[1])
                if month_str in month_map:
                    month = month_map[month_str]
                    return datetime(year, month, 1)

    # Check if it's 2019 and in second half based on text
    if '2019' in date_str:
        if any(month in date_str.lower() for month in ['jul', 'aug', 'sep', 'oct', 'nov', 'dec']):
            return datetime(2019, 7, 1)

    return None

# Parse CPC codes
def extract_cpc_codes(cpc_json):
