                year = int(groups[1])
                if month_str in month_map:
                    month = month_map[month_str]
                    return datetime(year, month, 1)

    # Check if it's 2019 and in second half based on text
    if '2019' in date_str:
        if any(month in date_str.lower() for month in ['jul', 'aug', 'sep', 'oct', 'nov', 'dec']):
