                    month = month_map[month_str]
                    return datetime(year, month, day)
            elif len(groups) == 2:
                month_str = groups[0][:3].lower()
                year = int(groups[1])
                if month_str in month_map:
                    month = month_map[month_str]
                    return datetime(year, month, 1)

    # Check if it's 2019 and in second half based on text
    if '2019' in date_str:
        if any(month in date_str.lower() for month in ['jul', 'aug', 'sep', 'oct', 'nov', 'dec']):
            return datetime(2019, 7, 1)

    return None

# Parse CPC codes
def extract_cpc_codes(cpc_json):
    try:
        if isinstance(cpc_json, str):
            cpc_list = json.loads(cpc_json)
        else:
            cpc_list = cpc_json
        return [item['code'] for item in cpc_list if 'code' in item]
    except:
        return []

# Process patents
patent_data = []
for patent in german_patents:
    grant_date = parse_grant_date(patent['grant_date'])
    if grant_date and grant_date.year == 2019 and grant_date.month >= 7:
