        for cpc in cpc_codes:
            cpc_level4 = get_cpc_level4(cpc)
            if cpc_level4:
                patent_data.append({
                    'cpc_level4': cpc_level4,
                    'cpc_full': cpc,
                    'patent_info': patent.get('Patents_info', '')
                })

